userDefinedLinkHintCss:
/*
Dracula / Alucard theme for Vimium
Automatically switches based on system theme.
Colors per official Dracula spec: https://draculatheme.com/spec
*/
:root {
  /* Dracula Classic */
  --bg: #282a36;          /* Background */
  --fg: #f8f8f2;          /* Foreground */
  --bg-secondary: #44475a;/* Selection */
  --selection: #6272a4;   /* Current Line (used for highlighted row) */
  --comment: #6272a4;     /* Comment */
  --red: #ff5555;
  --orange: #ffb86c;
  --yellow: #f1fa8c;
  --green: #50fa7b;
  --cyan: #8be9fd;
  --purple: #bd93f9;
  --pink: #ff79c6;
  --shadow: rgba(0, 0, 0, 0.4);
}
@media (prefers-color-scheme: light) {
  :root {
    /* Alucard Classic */
    --bg: #fffbeb;
    --fg: #1f1f1f;
    --bg-secondary: #cfcfde;
    --selection: #cfcfde;
    --comment: #6c664b;
    --red: #cb3a2a;
    --orange: #a34d14;
    --yellow: #846e15;
    --green: #14710a;
    --cyan: #036a96;
    --purple: #644ac9;
    --pink: #a3144d;
    --shadow: rgba(0, 0, 0, 0.15);
  }
}
/* Link hint boxes */
div > .vimiumHintMarker {
  background: var(--bg);
  font-size: 12px;
  border: 0.25em solid var(--orange);
  border-radius: 0.34em;
  box-shadow: 0em 0.1em 0.6em 0.1em var(--shadow);
}
div > .vimiumHintMarker span {
  color: var(--fg);
  font-size: inherit;
  text-shadow: none;
}
div > .vimiumHintMarker > .matchingCharacter {
  color: var(--comment);
}
/* HUD */
div.vimiumHUD {
  background: var(--bg);
  border: 1px solid var(--comment);
}
div.vimiumHUD .vimiumHUDSearchArea {
  background: var(--bg);
}
div.vimiumHUD .hud-find {
  background: var(--bg);
  border: none;
  color: var(--fg);
}
div.vimiumHUD span#hud-find-input{
  color: var(--fg);
}
div.vimiumHUD span#hud-match-count {
  color: var(--comment);
}
div.vimiumHUD .vimiumHUDSearchAreaInner {
  color: var(--comment);
}
/* Vomnibar */
#vomnibar{
  background-color: var(--bg-secondary);
}
#vomnibar input {
  color: var(--fg);
  font: -moz-window;
  font-size: 20px;
  height: 34px;
  margin-bottom: 0;
  padding: 4px;
  background-color: var(--bg);
  border-radius: 3px;
  border: 1px solid var(--comment);
  box-shadow: var(--pink) 0px 0px 1px;
  width: 100%;
  outline: none;
  box-sizing: border-box;
}
#vomnibar .vomnibarSearchArea {
  display: block;
  padding: 10px;
  background-color: var(--selection);
  border-radius: 4px 4px 0 0;
  border-bottom: 0px solid var(--pink);
}
#vomnibar ul {
  background-color: var(--bg-secondary);
  border-radius: 0 0 4px 4px;
  list-style: none;
  padding-top: 0;
  padding-bottom: 0;
  margin-block-start: 2px;
  margin-block-end: 0px;
}
#vomnibar li {
  border-bottom: 1px solid var(--comment);
  line-height: 1.1em;
  padding: 7px 10px;
  font-size: 16px;
  color: var(--fg);
  position: relative;
  display: list-item;
  margin: auto;
}
#vomnibar li .vomnibarBottomHalf {
  font-size: 15px;
  margin-top: 3px;
  padding: 2px 0;
}
#vomnibar li .vomnibarSource {
  color: var(--pink);
  margin-right: 4px;
}
#vomnibar li .vomnibarRelevancy {
  position: absolute;
  right: 0;
  top: 0;
  padding: 5px;
  background-color: var(--bg);
  color: var(--fg);
  font-family: monospace;
  width: 100px;
  overflow: hidden;
}
#vomnibar li .vomnibarUrl {
  white-space: nowrap;
  color: var(--green);
}
#vomnibar li .vomnibarMatch {
  font-weight: bold;
  color: var(--orange);
}
#vomnibar li em, #vomnibar li .vomnibarTitle {
  color: var(--fg);
  margin-left: 4px;
  font-weight: normal;
}
#vomnibar li em { font-style: italic; }
#vomnibar li em .vomnibarMatch, #vomnibar li .vomnibarTitle .vomnibarMatch {
  color: var(--orange);
}
#vomnibar li.vomnibarSelected {
  background-color: var(--selection);
  font-weight: normal;
}
#vomnibarInput::selection {
  background-color: var(--cyan);
}
